'use client';

import { useState, useTransition } from 'react';
import { addVideo } from '@/app/actions/admin';
import { X, Plus, Loader2, Video, Save, Play, Globe, Tag, Info } from 'lucide-react';

export default function AddVideoForm() {
  const [open, setOpen] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setError(null);
    const form = e.currentTarget;
    const formData = new FormData(form);

    startTransition(async () => {
      const result = await addVideo(formData);
      if (result.success) {
        form.reset();
        setOpen(false);
      } else {
        setError(result.error || 'Something went wrong.');
      }
    });
  }

  return (
    <>
      <button
        onClick={() => setOpen(true)}
        className="flex items-center gap-2 px-6 py-2.5 bg-saffron text-white rounded-xl hover:bg-saffron-dark transition-all font-bold text-sm shadow-[0_0_20px_rgba(245,158,11,0.3)] hover:shadow-[0_0_30px_rgba(245,158,11,0.5)] active:scale-95 group"
      >
        <Plus size={18} className="group-hover:rotate-90 transition-transform duration-300" />
        Add Video
      </button>

      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-[#0A1A10]/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white/[0.03] border border-white/10 rounded-[2.5rem] w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col backdrop-blur-2xl shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-saffron/10 rounded-2xl flex items-center justify-center border border-saffron/20 shadow-[0_0_15px_rgba(245,158,11,0.1)]">
                  <Video size={24} className="text-saffron" />
                </div>
                <div>
                  <h2 className="text-2xl font-bold font-heading text-white tracking-tight">Add New Video</h2>
                  <p className="text-white/40 text-xs font-medium italic">Share sacred teachings through motion</p>
                </div>
              </div>
              <button
                onClick={() => setOpen(false)}
                className="w-10 h-10 flex items-center justify-center text-white/40 hover:text-white hover:bg-white/10 rounded-xl transition-all"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto scrollbar-hide">
              {error && (
                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm font-medium flex items-center gap-3">
                  <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />
                  {error}
                </div>
              )}

              <div className="space-y-2">
                <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                  Video Title
                </label>
                <input
                  name="title"
                  required
                  placeholder="e.g. Yoga Nidra - Deep Relaxation"
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all shadow-inner"
                />
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                  YouTube URL
                </label>
                <div className="relative">
                  <Play size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                  <input
                    name="youtube_url"
                    required
                    type="url"
                    placeholder="https://www.youtube.com/watch?v=..."
                    className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all text-sm"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">Description</label>
                <textarea
                  name="description"
                  rows={3}
                  placeholder="Briefly describe the video content..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-4 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all text-sm resize-none scrollbar-hide"
                />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">Genre / Category</label>
                  <select
                    name="genre"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-saffron/50 transition-all appearance-none cursor-pointer"
                  >
                    <option value="" className="bg-[#0A1A10]">Select genre</option>
                    <option value="Hatha Yoga" className="bg-[#0A1A10]">Hatha Yoga</option>
                    <option value="Pranayama" className="bg-[#0A1A10]">Pranayama</option>
                    <option value="Meditation" className="bg-[#0A1A10]">Meditation</option>
                    <option value="Yoga Nidra" className="bg-[#0A1A10]">Yoga Nidra</option>
                    <option value="Philosophy" className="bg-[#0A1A10]">Philosophy</option>
                    <option value="Bhakti" className="bg-[#0A1A10]">Bhakti</option>
                    <option value="Kundalini" className="bg-[#0A1A10]">Kundalini</option>
                    <option value="Mantra" className="bg-[#0A1A10]">Mantra</option>
                    <option value="Discourse" className="bg-[#0A1A10]">Discourse</option>
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">Status</label>
                  <select
                    name="status"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-saffron/50 transition-all appearance-none cursor-pointer"
                  >
                    <option value="draft" className="bg-[#0A1A10]">Draft</option>
                    <option value="published" className="bg-[#0A1A10]">Published</option>
                  </select>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">Thumbnail URL</label>
                <div className="relative">
                  <Globe size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                  <input
                    name="thumbnail_url"
                    type="url"
                    placeholder="https://... (optional, auto-generated)"
                    className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all text-sm"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">Tags</label>
                <div className="relative">
                  <Tag size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                  <input
                    name="tags"
                    placeholder="yoga, meditation, pranayama (comma separated)"
                    className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all text-sm"
                  />
                </div>
              </div>

              <div className="flex items-center gap-3 bg-white/5 p-4 rounded-xl border border-white/10 group hover:bg-white/10 transition-all cursor-pointer">
                <div className="relative">
                  <input
                    type="checkbox"
                    name="is_own_content"
                    id="is_own_content"
                    value="true"
                    className="peer w-5 h-5 opacity-0 absolute cursor-pointer"
                  />
                  <div className="w-5 h-5 border-2 border-white/20 rounded peer-checked:bg-saffron peer-checked:border-saffron transition-all flex items-center justify-center">
                    <div className="w-2 h-2 bg-white rounded-full opacity-0 peer-checked:opacity-100 transition-all" />
                  </div>
                </div>
                <label htmlFor="is_own_content" className="text-sm font-medium text-white/60 group-hover:text-white transition-colors cursor-pointer">
                  This is our own original content
                </label>
              </div>

              <div className="pt-6 flex justify-end gap-4 border-t border-white/5 bg-white/[0.01] -mx-8 -mb-8 p-8">
                <button
                  type="button"
                  onClick={() => setOpen(false)}
                  className="px-6 py-3 text-white/60 hover:text-white hover:bg-white/5 rounded-xl font-bold text-sm transition-all"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={isPending}
                  className="flex items-center gap-2 px-8 py-3 bg-saffron text-white rounded-xl hover:bg-saffron-dark font-bold text-sm transition-all disabled:opacity-50 shadow-[0_0_20px_rgba(245,158,11,0.2)] hover:shadow-[0_0_30px_rgba(245,158,11,0.4)] active:scale-95"
                >
                  {isPending ? (
                    <>
                      <Loader2 size={18} className="animate-spin" />
                      Saving...
                    </>
                  ) : (
                    <>
                      <Save size={18} />
                      Add Video
                    </>
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
}
